<?php declare(strict_types=1);
namespace App\Services;
final class StreamingProfileService { public function select(array $media,?string $name=null):array{$config=config('profiles');$name=$name?:$config['default'];$profile=$config['profiles'][$name]??$config['profiles']['auto'];if($name!=='auto')return array_merge(['name'=>$name],$profile);$requiresPerformanceProfile=$media['height']>1080||($media['height']>=1080&&$media['fps']>30);return ['name'=>'auto','resolution'=>$requiresPerformanceProfile?$config['adaptive']['maximum_resolution']:config('stream.default_resolution'),'fps'=>$requiresPerformanceProfile?$config['adaptive']['maximum_fps']:config('ffmpeg.fps'),'preset'=>$requiresPerformanceProfile?$config['adaptive']['high_input_preset']:config('ffmpeg.preset'),'bitrate'=>config('stream.default_bitrate')];} public function selectForPlaylist(array $metadata,?string $name=null):array{if(!$metadata)throw new \InvalidArgumentException('Playlist metadata is required.');$highest=$metadata[0];foreach($metadata as $item)if($item['height']>$highest['height']||($item['height']===$highest['height']&&$item['fps']>$highest['fps']))$highest=$item;$profile=$this->select($highest,$name);$profile['source_metadata']=$metadata;$profile['highest_input']=$highest;return $profile;} }
